// ── Helper lookups ─────────────────────────────
export function getUserName(userId: string | null): string {
  if (!userId) return 'Unassigned';
  return seedUsers.find(u => u.user_id === userId)?.full_name ?? 'Unknown';
}

export function getNotesForEntity(entityType: EntityType, entityId: string): Note[] {
  return seedNotes.filter(n => n.entity_type === entityType && n.entity_id === entityId);
}

export function getCalendarEventsForEntity(entityType: EntityType, entityId: string): CalendarEvent[] {
  return seedCalendarEvents.filter(e => e.entity_type === entityType && e.entity_id === entityId);
}

export function getNextUpcomingEvent(entityType: EntityType, entityId: string): CalendarEvent | undefined {
  return seedCalendarEvents
    .filter(e => e.entity_type === entityType && e.entity_id === entityId && e.status === CalendarEventStatus.UPCOMING)
    .sort((a, b) => new Date(a.scheduled_at).getTime() - new Date(b.scheduled_at).getTime())[0];
}
